wp_send_json_error(
                array(
                    'message' => __( 'Could not generate auth URL', 'hostinger-reach' ),
                )
            )

array_map(
            function ( Forminator_Form_Entry_Model $entry ) use ( $form_id ) {
                $contact = new ReachContact(
                    $this->find_email( $entry->meta_data ),
                    '',
                    '',
                    array(
                        'plugin'  => self::INTEGRATION_NAME,
                        'form_id' => $form_id,
                        'group'   => $this->get_form_title( $form_id ),
                    )
                );

                return $contact->to_array();
            },
            $entries
        )

array_map(
            function ( $post ) {
                $form = new Form(
                    array(
                        'form_id'     => $post->ID,
                        'post_id'     => $post->ID,
                        'type'        => $this->get_name(),
                        'is_active'   => $this->is_form_valid( $post ) && $this->is_form_enabled( $post->ID ),
                        'submissions' => (int) get_post_meta( $post->ID, Integration::HOSTINGER_REACH_SUBMISSIONS_META_KEY, true ),
                    )
                );

                return $form->to_array();
            },
            $posts
        )

array_map(
            function ( $form ) {
                $form_obj = new Form(
                    array(
                        'form_id'     => $form->get_id(),
                        'form_title'  => $form->get_setting( 'title' ),
                        'is_active'   => $this->is_form_enabled( $form->get_id() ),
                        'submissions' => $this->get_submissions( $form ),
                        'type'        => $this->get_name(),
                        'post_id'     => null,
                    )
                );

                return $form_obj->to_array();
            },
            $forms_data
        )

array_map(
            function ( string $email ) use ( $form, $form_id ) {
                $title = $form->get_setting( 'title' );
                if ( empty( $title ) ) {
                    $title = $form_id . ' ' . self::INTEGRATION_NAME;
                }
                $contact = new ReachContact(
                    $email,
                    '',
                    '',
                    array(
                        'plugin' => self::INTEGRATION_NAME,
                        'group'  => $title,
                    )
                );

                return $contact->to_array();
            },
            $entries
        )

array_map(
            function ( mixed $lead ) use ( $form_id ) {
                $contact = new ReachContact(
                    $lead->email,
                    $lead?->fist_name ?? '',
                    $lead?->last_name ?? '',
                    array(
                        'plugin'  => self::INTEGRATION_NAME,
                        'form_id' => $form_id,
                    )
                );

                return $contact->to_array();
            },
            $leads->leads ?? array()
        )

array_map(
            function ( array $entry ) use ( $form_id ) {
                $contact = new ReachContact(
                    $this->find_email( $entry['form_data'] ?? array() ),
                    '',
                    '',
                    array(
                        'plugin'  => self::INTEGRATION_NAME,
                        'form_id' => $form_id,
                        'group'   => $this->get_form_title( $form_id ),
                    )
                );

                return $contact->to_array();
            },
            $entries
        )

array_map(
            function ( array $entry ) {
                $contact = new ReachContact(
                    $entry['email'] ?? '',
                    $entry['name'] ?? '',
                    '',
                    array(
                        'plugin' => self::INTEGRATION_NAME,
                        'group'  => self::INTEGRATION_NAME,
                    )
                );

                return $contact->to_array();
            },
            $entries
        )

array_map(
            function ( stdClass $user ) {
                return array(
                    'email'    => $user->email ?? '',
                    'name'     => $user->first_name ?? '',
                    'metadata' => array(
                        'form_id' => wc_get_page_id( 'checkout' ),
                        'plugin'  => self::INTEGRATION_NAME,
                        'group'   => self::INTEGRATION_NAME,
                    ),
                );
            },
            // phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared
            $wpdb->get_results( $sql )
        )

array_map(
            function ( $cart ) use ( $columns ) {
                return array_intersect_key( $cart, array_flip( $columns ) );
            },
            $carts
        )

$wpdb->query(
            $wpdb->prepare(
                "DELETE FROM {$wpdb->options}
                 WHERE option_name LIKE %s
                 AND option_name != %s",
                $wpdb->esc_like( $optionPrefix . $eventAction . '_' ) . '%',
                $todayOption
            )
        )

printf(
			wp_kses(
				// translators: 1) is the number of affected actions, 2) is a link to an admin screen.
				_n(
					'<strong>Action Scheduler:</strong> %1$d <a href="%2$s">past-due action</a> found; something may be wrong. <a href="https://actionscheduler.org/faq/#my-site-has-past-due-actions-what-can-i-do" target="_blank">Read documentation &raquo;</a>',
					'<strong>Action Scheduler:</strong> %1$d <a href="%2$s">past-due actions</a> found; something may be wrong. <a href="https://actionscheduler.org/faq/#my-site-has-past-due-actions-what-can-i-do" target="_blank">Read documentation &raquo;</a>',
					$num_pastdue_actions,
					'action-scheduler'
				),
				array(
					'strong' => array(),
					'a'      => array(
						'href'   => true,
						'target' => true,
					),
				)
			),
			absint( $num_pastdue_actions ),
			esc_attr( esc_url( $actions_url ) )
		)

